import { SeedApiClient } from "../../src/Client";
import { mockServerPool } from "../mock-server/MockServerPool";

describe("SeedApiClient", () => {
    test("chat_stream", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedApiClient({ maxRetries: 0, environment: server.baseUrl });
        const rawRequestBody = { prompt: "prompt", stream: true };
        const rawResponseBody = 'event: \ndata: {"delta":"delta","tokens":1}\n\n';

        server
            .mockEndpoint()
            .post("/chat")
            .jsonBody(rawRequestBody)
            .respondWith()
            .statusCode(200)
            .sseBody(rawResponseBody)
            .build();

        const response = await client.chatStream({
            prompt: "prompt",
        });
        const events: unknown[] = [];
        for await (const event of response) {
            events.push(event);
        }
        expect(events).toEqual([{ delta: "delta", tokens: 1 }]);
    });

    test("chat", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedApiClient({ maxRetries: 0, environment: server.baseUrl });
        const rawRequestBody = { prompt: "Hello" };
        const rawResponseBody = { message: "Hello! How can I help you?", finish_reason: "complete" };

        server
            .mockEndpoint()
            .post("/chat")
            .jsonBody(rawRequestBody)
            .respondWith()
            .statusCode(200)
            .jsonBody(rawResponseBody)
            .build();

        const response = await client.chat({
            prompt: "Hello",
        });
        expect(response).toEqual({
            message: "Hello! How can I help you?",
            finish_reason: "complete",
        });
    });
});
